public int minNonZeroProduct(int p) {
    int mod = 1000000007;
    long x = (1L << p) - 1;
    long y = (1L << p) - 2;
    long z = modPow(y, x - 1, mod);
    return (int) (x * z % mod);
}

private long modPow(long x, long y, int mod) {
    long res = 1L;
    while (y > 0) {
        if ((y & 1) == 1) {
            res = res * x % mod;
        }
        x = x * x % mod;
        y >>= 1;
    }
    return res;
}
